WHERE id = #{id}

mapper.select:

WHERE g.category_id = #{categoryId}
GROUP BY g.id, g.category_id, c.name, g.name,
g.min_players, g.max_players, g.play_time, g.is_active
ORDER BY g.id
LIMIT #{pageRequestDTO.size} OFFSET #{pageRequestDTO.skip}


WHERE g.is_active = #{isActive}

    AND g.category_id = #{categoryId}

GROUP BY g.id, g.category_id, c.name, g.name,
g.min_players, g.max_players, g.play_time, g.is_active
ORDER BY g.id
LIMIT #{pageRequestDTO.size} OFFSET #{pageRequestDTO.skip}

